class ParentWidget extends StatefulWidget {
  @override
  _ParentWidgetState createState() => _ParentWidgetState();
}

class _ParentWidgetState extends State<ParentWidget> {
  bool _isActive = false;

  void _toggleActive() {
    setState(() {
      _isActive = !_isActive;
    });
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        ChildA(isActive: _isActive),
        ChildB(onToggle: _toggleActive),
      ],
    );
  }
}

class ChildA extends StatelessWidget {
  final bool isActive;
  ChildA({required this.isActive});
  @override
  Widget build(BuildContext context) {
    return Text(isActive ? 'Active' : 'Inactive');
  }
}

class ChildB extends StatelessWidget {
  final VoidCallback onToggle;
  ChildB({required this.onToggle});
  @override
  Widget build(BuildContext context) {
    return ElevatedButton(onPressed: onToggle, child: Text('Toggle'));
  }
}
